{"name": "github_issue_comment_watcher", "kind": "polling", "polling_interval": "30s", "description": "每30秒轮询 GitHub Issue 评论区。通过 since cursor（上一条评论的 created_at）避免重复触发。传入 owner、repo、issue_number，以及可选的 since 游标。返回新增评论列表 + 更新后的 cursor。", "code": "import httpx
from datetime import datetime, timezone


def main(
    owner: str,
    repo: str,
    issue_number: int,
    since: str | None = None,
    github_token: str | None = None,
) -> dict:
    """
    轮询 GitHub Issue 评论。

    参数:
        owner: 仓库所有者
        repo: 仓库名称
        issue_number: Issue 编号
        since: ISO-8601 时间戳 cursor。如果提供，只返回该时间之后的评论。
               建议每次调用后将返回值的 "cursor" 字段传回此参数，实现去重。

    返回:
        {
            "new_comments": [ ... ],   # 新增评论列表（按 created_at 升序）
            "cursor": "2025-01-01T00:00:00Z",  # 最新一条评论的 created_at，用于下次传入 since
            "count": 2                 # 本次新增数量
        }
    """
    headers = {
        "Accept": "application/vnd.github.v3+json",
        "User-Agent": "Forgify-Poller/1.0",
    }
    if github_token:
        headers["Authorization"] = f"Bearer {github_token}"

    params = {
        "per_page": 100,
        "sort": "created",
        "direction": "asc",  # 升序，最早的在前，最新的在后
    }
    if since:
        params["since"] = since

    url = f"https://api.github.com/repos/{owner}/{repo}/issues/{issue_number}/comments"

    try:
        with httpx.Client(timeout=30.0) as client:
            resp = client.get(url, headers=headers, params=params)
            resp.raise_for_status()
            comments = resp.json()
    except httpx.HTTPStatusError as e:
        return {
            "new_comments": [],
            "cursor": since,
            "count": 0,
            "error": f"GitHub API error: {e.response.status_code} - {e.response.text}",
        }
    except httpx.RequestError as e:
        return {
            "new_comments": [],
            "cursor": since,
            "count": 0,
            "error": f"Network error: {str(e)}",
        }

    new_cursor = since  # 如果没有新评论，cursor 保持不变
    if comments:
        # comments 按 asc 排序，最后一条是最新的
        new_cursor = comments[-1]["created_at"]

    return {
        "new_comments": comments,
        "cursor": new_cursor,
        "count": len(comments),
    }
"}
